INSERT INTO legacy_meridian_syndromes (nhomid, tieuket, trieuchung, benhly, phuyet_chamcuu, giainghia_phuyet, duyet, tieutruong_c8, tieutruong, tieutruong_c11, tam_c8, tam, tam_c11, tamtieu_c8, tamtieu, tamtieu_c11, tambao_c8, tambao, tambao_c11, daitrang_c8, daitrang, daitrang_c11, phe_c8, phe, phe_c11, bangquang_c8, bangquang, bangquang_c11, than_c8, than, than_c11, dam_c8, dam, dam_c11, vi_c8, vi, vi_c11, can_c8, can, can_c11, ty_c8, ty, ty_c11) VALUES (20, E'Oan uất thành bệnh', E'Đông y học cho rằng nguyên nhân gây bệnh nói chung có nội nhân, ngoại nhân, bất nội ngoại nhân. Ngoại nhân là ngoại cảm lục dâm, nội dâm là nội thương thất tình. Bài này bàn đến số bệnh do các loại tình cảm: Tức giận, lo nghĩ, tiếc xót, buồn, nghi ngờ, oan uất mà làm thành bệnh, chúng thuộc về nội nhân, nội thương thất tình.
