INSERT INTO legacy_meridian_syndromes (nhomid, tieuket, trieuchung, benhly, phuyet_chamcuu, giainghia_phuyet, duyet, tieutruong_c8, tieutruong, tieutruong_c11, tam_c8, tam, tam_c11, tamtieu_c8, tamtieu, tamtieu_c11, tambao_c8, tambao, tambao_c11, daitrang_c8, daitrang, daitrang_c11, phe_c8, phe, phe_c11, bangquang_c8, bangquang, bangquang_c11, than_c8, than, than_c11, dam_c8, dam, dam_c11, vi_c8, vi, vi_c11, can_c8, can, can_c11, ty_c8, ty, ty_c11) VALUES (12, E'Yêu thống (bệnh đau lưng)', E'Đau lưng là bệnh thường gặp ở mọi giới, mọi lứa tuổi và do nhiều nguyên nhân. Trong này chỉ giới thiệu mấy loại đau lưng thường thấy (ngoại trừ lao xương và tổn thương va đập):
	- Đau lưng do viêm đại tràng và trĩ.
 	- Đau lưng do thoái hoá đĩa đệm cột sống thắt lưng.
	- Đau lưng do thận hư.
	- Đau lưng do bê vật nặng, tổn thương phần mềm vùng thắt lưng.', E'đau một hoặc hai bên vùng thắt lưng là một chứng trạng do nhiều loại bệnh gây ra, bao gồm bệnh của thận, bộ máy sinh dục, bệnh ở cơ lưng, cột sống, tuỷ sống, kể cả ngoại thương ở cơ lưng và đốt sống lưng. y học cổ phương Đông cho rằng “ lưng là phủ của thận”, do đó, đau lưng và thận có quan hệ mật thiết. Nếu bị ngoại tà hàn thấp, thấp nhiệt, hoặc bê nặng mà trượt ngã, làm cho tà vướng, ứ trệ khí huyết, kinh lạc bất hoà, hoặc nhân người yếu bị bệnh lâu dài, tuổi già tinh huyết bất túc, thận tinh hao hư, không thể nuôi dưỡng kinh mạch, đều có thể dẫn đến đau lưng. Chương này coi trọng biện chứng thí trị tất cả các loại đau lưng, còn phần bệnh tất khác nhau dẫn đến đau lưng, có thể tham khảo thương khoa, nội khoa, phụ khoa hữu quan.
*ĐIỂM CHỦ YẾU ĐỂ KIỂM TRA.
	Hỏi tiền sử, chú ý vùng đau lưng, tính chất đau, quan hệ giữa chúng với khí hậu và lao động, do đâu mà phát đau và những chứng trạng kèm theo, kiểm tra đốt sống, cơ lưng, khi cần thiết phải khám phụ khoa, xét nghiệm máu và nước tiểu, chụp phim cột sống đẻ phân biệt các nguyên nhân khác nhau.
1. Do ngoại thương dẫn đến đau lưng, trong ngoại thương, có ngoại thương trực tiếp dẫn đến gẫy xương kín hoặc hở, ngoại thương dẫn đến thoát vị đĩa đệm, loại phong thấp viêm khớp, viêm xùi to đốt sống, lao đốt sống. Trên lâm sàng có thể theo tính chất đau, tuổi phát bệnh khác nhau, kết hợp với tiền sử và phim chụp cột sống, để chẩn đoán phân biệt.
2. nếu đau đớn ở hai bên thắt lưng là chính, thường thuộc bệnh ở cơ lưng như khởi bệnh khẩn cấp,có tiền sử ngoại thương, đau rất dữ, hoạt động bị vướng, hoặc cục bộ da bầm tím, thường thuộc bong gân cấp tính, khởi bệnh từ từ, vùng thắt lưng buốt đau, khi trời âm u hoặc sau khi làm mệt đau tăng mạnh, thường là bệnh phong thấp, cơ lưng bị lao tổn mạn tính.
3. Đau thắt lưng có kèm theo đái đau, đái nhiều lần, đái vội, đái ra máu, hoặc có sốt, phải nghĩ đến bệnh ở hệ tiết niệu. Đau lưng có liên quan kinh nguyệt, hoặc kèm theo khí hư rất nhiều, phải nghĩ đến bệnh phụ khoa.', E'Cách chữa bằng huyệt vị:
ấn day ở mệnh môn và áp thống điểm (Nơi này thấy đau) ấn từ nhẹ đến nặng, từ 1-2 phút, xoa ở thận du 10 phút, cuối cùng day ở huyệt Uỷ trung.
Bằng châm cứu:
a. Thể châm.
- Phong thấp hàn chứng: Thận tích yêu dương quan, âm môn, Uỷ trung hoặc lấy A thi huyệt. Châm xong, những huyệt ở vùng thắt lưng có thể cứu thêm hoặc làm bầu giác.
- Thận hư: Thận du (Châm cứu) Mệnh môn (cứu)Thái khê
- Cơ lưng lao tổn : thận tích, yêu nhỡn, uỷ trung .
- Bong gân cấp tính: nhân trugn, Uỷ trung, (Chích trung)
- Châm trên bàn tay: yêu thoái điểm 9 trên mu bàn tay, trước nếp cổ tay 1,5 thốn ở khe gây cơ duỗi ngón 2 phía cạch quany và gân cơ duỗi ngón 4 ở cạnh trụ, cộng là 4 diểm (hai)
b, Nhĩ châm: giao cảm, Thần môn, Yêu (Thắt lưng) Thận
Phương châm nghiệm (Kinh huyệt)
